               "questionNumber":1,
               "text":"Preparation of Income Statement and Statement of Financial Position",
               "type":"open-ended",
               "points":20,
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"Prepare the income statement for the year ended 31 December 2025",
                     "type":"open-ended",
                     "points":10,
                     "correctAnswer":"Sales Revenue: 20,000,000, Cost of Goods Sold: 9,000,000, Gross Profit: 11,000,000, Operating Expenses: 4,700,000, Net Profit: 6,300,000"
                  },
                  {
                     "label":"b)",
                     "text":"Prepare the statement of financial position as at 31 December 2025",
                     "type":"open-ended",
                     "points":10,
                     "correctAnswer":"Current Assets: 13,000,000, Non-current Assets: 8,800,000, Total Assets: 21,800,000, Equity: 21,300,000, Current Liabilities: 3,000,000, Total Equity and Liabilities: 24,300,000"
                  }
               ],
               "correctAnswer":"a) Sales Revenue: 20,000,000, Cost of Goods Sold: 9,000,000, Gross Profit: 11,000,000, Operating Expenses: 4,700,000, Net Profit: 6,300,000; b) Current Assets: 13,000,000, Non-current Assets: 8,800,000, Total Assets: 21,800,000, Equity: 21,300,000, Current Liabilities: 3,000,000, Total Equity and Liabilities: 24,300,000"
            }
         ]
      },
      {
         "name":"B",
         "title":"Financial Statement Analysis (30 Marks)",
         "description":"Analyze financial data",
