         "questions":[
            {
               "questionNumber":2,
               "text":"Financial Statement Analysis",
               "type":"open-ended",
               "points":30,
               "subQuestions":[
                  {
                     "label":"a)",
                     "text":"Calculate the current ratio for 2025",
                     "type":"open-ended",
                     "points":5,
                     "correctAnswer":"2:1"
                  },
                  {
                     "label":"b)",
                     "text":"Calculate the net profit margin for 2025",
                     "type":"open-ended",
                     "points":5,
                     "correctAnswer":"12%"
                  },
                  {
                     "label":"c)",
                     "text":"Calculate the return on assets (ROA) for 2025",
                     "type":"open-ended",
                     "points":5,
                     "correctAnswer":"24%"
                  },
                  {
                     "label":"d)",
                     "text":"Calculate the debt ratio for 2025",
                     "type":"open-ended",
                     "points":5,
                     "correctAnswer":"40%"
                  },
                  {
                     "label":"e)",
                     "text":"Calculate the percentage increase in sales from 2024 to 2025",
                     "type":"open-ended",
                     "points":5,
                     "correctAnswer":"20%"
                  }
               ],
               "correctAnswer":"a) 2:1; b) 12%; c) 24%; d) 40%; e) 20%"
